#include <pthread.h>
#include <stdio.h>
#include <stdlib.h>

void* threadFunction(void* arg) {
    int* num = (int*)arg;
    printf("Thread %d started\n", *num);
    for(int i = 0; i < 5; i++) {
        printf("Thread %d: iteration %d\n", *num, i);
    }
    printf("Thread %d finished\n", *num);
    return NULL;
}

int main() {
    pthread_t threads[3];
    int threadArgs[3] = {1, 2, 3};

    // Create 3 threads
    for(int i = 0; i < 3; i++) {
        pthread_create(&threads[i], NULL, threadFunction, &threadArgs[i]);
    }

    // Wait for all threads to complete
    for(int i = 0; i < 3; i++) {
        pthread_join(threads[i], NULL);
    }

    printf("All threads completed\n");
    return 0;
}
